// BUG: string "false" is a non-empty string → attribute IS present → still disabled
<input disabled="false" />  // ← Wrong

// Correct: use the boolean false
<input disabled={false} />   // ← attribute omitted, input enabled

const isAdmin = true;

function Avatar({ user }) {
  return (
    <img
      src={user.avatarUrl}                          // variable
      alt={`Profile photo of ${user.name}`}         // template literal
      width={isAdmin ? 64 : 48}                     // ternary
      style={{ border: isAdmin ? "2px solid gold" : "none" }} // object literal
      aria-label={`Avatar for ${user.name}`}
    />
  );
}

// id is omitted when userId is null or undefined
<section id={userId || null} />

// Conditional aria attribute — omitted when not applicable
<li
  role="option"
  aria-selected={isSelected ? true : undefined}
/>

// Conditional disabled — cleaner than ternary
<button disabled={!formIsValid}>Submit</button>

// BUG: when list is empty, renders "0" on screen
<div>{list.length && <ItemList items={list} />}</div>

// Fix 1: explicit comparison
<div>{list.length > 0 && <ItemList items={list} />}</div>

// Fix 2: ternary
<div>{list.length ? <ItemList items={list} /> : null}</div>

// Fix 3: double-bang
<div>{!!list.length && <ItemList items={list} />}</div>

// Wrong — HTML attribute names
<div class="card">...</div>
<label for="email">...</label>

// Correct — JSX property names
<div className="card">...</div>
<label htmlFor="email">...</label>

// Dynamic className
<button className={`btn ${variant} ${disabled ? 'btn-disabled' : ''}`}>
  {label}
</button>

// Wrong — string (HTML-style)
<button onclick="handleClick()">Click</button>

// Correct — function expression
<button onClick={handleClick}>Click</button>
<button onClick={() => handleClick(item.id)}>Click</button>
<button onClick={(e) => { e.preventDefault(); submit(); }}>Submit</button>

// Controlled: React drives the value
function ControlledInput() {
  const [text, setText] = useState('');
  return (
    <input
      value={text}
      onChange={(e) => setText(e.target.value)}
    />
  );
}

// Uncontrolled: DOM drives the value after mount
function UncontrolledInput() {
  const ref = useRef(null);
  return (
    <input
      defaultValue="initial text"
      ref={ref}
    />
  );
}

import clsx from 'clsx';

function Button({ variant, size, disabled, className, children }) {
  return (
    <button
      className={clsx(
        'btn',                              // always present
        `btn-${variant}`,                   // dynamic segment
        size === 'lg' && 'btn-large',       // boolean expression
        disabled && 'btn-disabled',         // falsy = omitted
        className                           // caller override
      )}
      disabled={disabled}
    >
      {children}
    </button>
  );
}

// Correct: object with camelCase keys
<div style={{ color: 'red', fontSize: 16, marginTop: '1rem' }}>

// Wrong: CSS string (React warning)
<div style="color: red; font-size: 16px">

// Dynamic styles
const styles = {
  opacity: isVisible ? 1 : 0,
  transform: `translateX(${offset}px)`,
  transition: 'opacity 200ms ease',
};
<div style={styles}>

import { useRef, useEffect } from 'react';

function AutoFocusInput() {
  const inputRef = useRef(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  return <input ref={inputRef} type="text" />;
}

// Callback ref — receives the node directly
<input ref={(node) => {
  if (node) node.focus();
}} />

// Component
function SubmitButton({ isValid, isLoading }) {
  return (
    <button
      type="submit"
      disabled={!isValid || isLoading}
      aria-busy={isLoading}
      data-testid="submit-btn"
    >
      {isLoading ? 'Saving…' : 'Save'}
    </button>
  );
}

// Test (React Testing Library)
import { render, screen } from '@testing-library/react';

test('disables button when form is invalid', () => {
  render(<SubmitButton isValid={false} isLoading={false} />);
  expect(screen.getByTestId('submit-btn')).toBeDisabled();
});

test('sets aria-busy during loading', () => {
  render(<SubmitButton isValid={true} isLoading={true} />);
  expect(screen.getByRole('button')).toHaveAttribute('aria-busy', 'true');
});

// Problematic: new style object every render breaks React.memo
const MemoChild = React.memo(Child);

function Parent({ color }) {
  // new object reference each render → memo never bails out
  return <MemoChild style={{ color }} />;
}

// Fix 1: module-level constant for static values
const BASE_STYLE = { fontFamily: 'monospace', letterSpacing: 1 };
<MemoChild style={BASE_STYLE} />

// Fix 2: useMemo for values that depend on props/state
function Parent({ color }) {
  const style = useMemo(() => ({ color }), [color]);
  return <MemoChild style={style} />;
}

import type { InputHTMLAttributes } from 'react';

// Typed wrapper — all valid input attributes auto-complete
function Input(props: InputHTMLAttributes<HTMLInputElement>) {
  return <input {...props} />;
}

// TypeScript catches wrong types at compile time
<Input type="text" disabled={true} maxLength={100} />
<Input required />           // shorthand bool — TypeScript accepts it
// Error: Type 'string' is not assignable to type 'boolean | undefined'
<Input disabled="false" />

// SVG in JSX: camelCase attribute names
<svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg">
  <circle
    cx={50}
    cy={50}
    r={40}
    fill="skyblue"
    strokeWidth={2}          // stroke-width in HTML SVG
    strokeDasharray="5 3"    // stroke-dasharray in HTML SVG
  />
  <text
    x={50}
    y={55}
    textAnchor="middle"      // text-anchor in HTML SVG
    dominantBaseline="middle"
    fontSize={14}
  >
    Hello
  </text>
</svg>
